node -e '
const p = require("./paginate.js");
const items = ["a","b","c","d","e"];
const t = (label, got, want) => console.log((JSON.stringify(got)===JSON.stringify(want)?"PASS":"FAIL"), label, "->", JSON.stringify(got));
t("page=1 perPage=2 (normal)", p(items,1,2), ["a","b"]);
t("page=3 perPage=2 (partial last)", p(items,3,2), ["e"]);
t("page=0 (QA: was tail)", p(items,0,2), []);
t("page=-1 (negative)", p(items,-1,2), []);
t("page=99 past end (QA: was junk)", p(items,99,2), []);
t("string query params page=2 perPage=2", p(items,"2","2"), ["c","d"]);
t("empty query param page=\"\"", p(items,"",2), []);
t("perPage=0", p(items,1,0), []);
t("perPage NaN", p(items,1,"abc"), []);
t("items not array", p(null,1,2), []);
'

